dashboard_integration:
interface DashboardProps {
  searchParams: Promise<{
    dateFrom?: string;
    dateTo?: string;
    status?: string;
    branch?: string;
  }>;
}

export default async function Dashboard({ searchParams }: DashboardProps) {
  const params = await searchParams;
  const { dateFrom, dateTo, status, branch } = params;

  // Fetch data with date filters
  const metrics = await getDashboardMetrics(dateFrom, dateTo);
  const executions = await getExecutions({ dateFrom, dateTo, status, branch });
  const trends = await getTrendData(7, dateFrom, dateTo);

  return (
    <div>
      <DateRangePicker dateFrom={dateFrom} dateTo={dateTo} />
      {/* Dashboard components */}
    </div>
  );
}
